/// <summary>
///  extension class for form datasource AssetTable, AssetTable
/// </summary>
[ExtensionOf(formDataSourceStr(AssetTable, AssetTable))]
internal final class ETG_AssetTable_Extension
{
}

Method.Source:
/// <summary>
/// Calling new method updateDesignETG() in COC of standard active().
/// </summary>
/// <returns>int</returns>
int active()
{
    int ret =  next active();
    this.updateDesignETG();
    return ret;
}

/// <summary>
/// This method contains logic for disable/enable the ConversionToInventoryButton when cylinder tracking feature is enabled.
/// also for visibility of field Capexapprovalid when CapexApprovalId feature is enabled
/// </summary>
public void updateDesignETG()
{
    this.formRun().design().controlName(formControlStr(AssetTable, ETGConversionToInventory)).visible(SalesParameters::find().ETGEnableCylinderTracking);
    this.formRun().design().controlName(formControlStr(AssetTable, ETGCapexApprovalId)).visible(AssetParameters::find().ETGCapexApprovalIdFeature);
    this.formRun().design().controlName(formControlStr(AssetTable, Grid_ETGCapexApprovalId)).visible(AssetParameters::find().ETGCapexApprovalIdFeature);


}
